import{i as e,r as t,s as n,t as r}from"./app-CYVqc-L7.js";var i=JSON.parse(`{"path":"/frontend/webgl-mask.html","title":"WebGL Mask — webgl-mask.js","lang":"en-US","frontmatter":{},"git":{"updatedTime":1777718854000,"contributors":[{"name":"JaguarM","username":"JaguarM","email":"39597011+JaguarM@users.noreply.github.com","commits":5,"url":"https://github.com/JaguarM"}],"changelog":[{"hash":"f7379a270c9017587048bdc46c269272afc057f2","time":1777718854000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"updated documentation"},{"hash":"3ffbee9623e690b2489eecb53c82e380b06773a0","time":1775471641000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Fix Documentation links to GitHub URLs"},{"hash":"a267f4ad383509977e55b04d582225aecd2802d2","time":1775467276000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Updated Documentation"},{"hash":"3bbb491f17913ec6288159d2b53d03c92c805a63","time":1774704928000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Made that shit modular with django apps"},{"hash":"f7330e85197db34564e6215e1d272b22e506e24e","time":1774437245000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Add redaction detection backend and docs"}]},"filePathRelative":"frontend/webgl-mask.md"}`),a={name:`webgl-mask.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="webgl-mask-—-webgl-mask-js" tabindex="-1"><a class="header-anchor" href="#webgl-mask-—-webgl-mask-js"><span>WebGL Mask — <code>webgl-mask.js</code></span></a></h1><p><a href="https://github.com/JaguarM/EpsteinTool/blob/main/webgl_mask/static/webgl_mask/webgl-mask.js" target="_blank" rel="noopener noreferrer">webgl-mask.js</a> renders GPU-accelerated redaction mask overlays.</p><h2 id="architecture" tabindex="-1"><a class="header-anchor" href="#architecture"><span>Architecture</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">POST /webgl/masks</span>
<span class="line">    ↓</span>
<span class="line">\`state.maskImages\` populated with all base64 masks</span>
<span class="line">    ↓</span>
<span class="line">\`refreshWebGLCanvases()\`</span>
<span class="line">    ↓</span>
<span class="line">\`initWebGLOverlay()\` (for visible pages via IntersectionObserver)</span>
<span class="line">    ↓</span>
<span class="line">Two LUMINANCE textures: uPage (LINEAR) + uMask (NEAREST)</span>
<span class="line">    ↓</span>
<span class="line">Fragment shader: multiplicative alpha recovery → grayscale output</span>
<span class="line">    ↓</span>
<span class="line">CSS mix-blend-mode: normal — canvas composited directly over PDF</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h2><h3 id="fetchmasksasync-file-isdefault" tabindex="-1"><a class="header-anchor" href="#fetchmasksasync-file-isdefault"><span><code>fetchMasksAsync(file, isDefault)</code></span></a></h3><p>Asynchronously requests all masks from <code>/webgl/masks</code>. Stores results in <code>state.maskImages</code> and calls <code>refreshWebGLCanvases()</code>.</p><h3 id="setupwebgloverlay-pagecontainer-canvas-pagenum" tabindex="-1"><a class="header-anchor" href="#setupwebgloverlay-pagecontainer-canvas-pagenum"><span><code>setupWebGLOverlay(pageContainer, canvas, pageNum)</code></span></a></h3><p>Registers a page container with the <code>IntersectionObserver</code>. When a page becomes visible, <code>initWebGLOverlay(canvas, pageNum)</code> is called. Pages with no mask data are skipped until <code>refreshWebGLCanvases()</code> triggers after async load.</p><p><strong>Texture setup:</strong></p><ul><li>Format: <code>gl.LUMINANCE</code> (single-channel grayscale)</li><li>Page texture: <code>gl.LINEAR</code> filtering</li><li>Mask texture: <code>gl.NEAREST</code> filtering (preserves hard pixel boundaries)</li><li>Wrapping: <code>gl.CLAMP_TO_EDGE</code></li></ul><h3 id="clearwebglcontexts" tabindex="-1"><a class="header-anchor" href="#clearwebglcontexts"><span><code>clearWebGLContexts()</code></span></a></h3><p>Destroys all active WebGL contexts. Called when navigating between documents.</p><h3 id="updatewebgluniforms-specificpage" tabindex="-1"><a class="header-anchor" href="#updatewebgluniforms-specificpage"><span><code>updateWebGLUniforms(specificPage?)</code></span></a></h3><p>Reads <code>els.edgeSubtract.value / 255.0</code> → <code>uStrength</code> uniform and redraws. No texture re-upload needed — instant 60fps updates.</p><h2 id="shaders" tabindex="-1"><a class="header-anchor" href="#shaders"><span>Shaders</span></a></h2><h3 id="vertex-shader" tabindex="-1"><a class="header-anchor" href="#vertex-shader"><span>Vertex Shader</span></a></h3><p>Draws a full-screen quad; maps clip-space coords to UV with Y-flip.</p><h3 id="fragment-shader" tabindex="-1"><a class="header-anchor" href="#fragment-shader"><span>Fragment Shader</span></a></h3><div class="language-glsl line-numbers-mode" data-highlighter="prismjs" data-ext="glsl"><pre><code class="language-glsl"><span class="line"><span class="token keyword">float</span> page <span class="token operator">=</span> <span class="token function">texture2D</span><span class="token punctuation">(</span>uPage<span class="token punctuation">,</span> vTexCoord<span class="token punctuation">)</span><span class="token punctuation">.</span>r<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">float</span> mask <span class="token operator">=</span> <span class="token function">texture2D</span><span class="token punctuation">(</span>uMask<span class="token punctuation">,</span> vTexCoord<span class="token punctuation">)</span><span class="token punctuation">.</span>r<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">float</span> alpha <span class="token operator">=</span> mask <span class="token operator">*</span> uStrength<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">float</span> result<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>mask <span class="token operator">&gt;</span> <span class="token number">0.999</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// Interior: fully covered, original unrecoverable — show white</span></span>
<span class="line">  result <span class="token operator">=</span> uStrength<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// Border/clear: invert anti-aliasing multiplication</span></span>
<span class="line">  result <span class="token operator">=</span> <span class="token function">min</span><span class="token punctuation">(</span>page <span class="token operator">/</span> <span class="token function">max</span><span class="token punctuation">(</span><span class="token number">1.0</span> <span class="token operator">-</span> alpha<span class="token punctuation">,</span> <span class="token number">0.001</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token number">1.0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">gl_FragColor <span class="token operator">=</span> <span class="token keyword">vec4</span><span class="token punctuation">(</span><span class="token keyword">vec3</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token number">1.0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Three pixel cases:</strong></p><table><thead><tr><th>Pixel type</th><th><code>mask</code></th><th>Behaviour</th></tr></thead><tbody><tr><td>Interior</td><td>1.0</td><td>Outputs <code>uStrength</code> (white at full slider)</td></tr><tr><td>Border</td><td>0 &lt; m &lt; 1</td><td><code>page / (1 - mask × strength)</code> — recovers original via division</td></tr><tr><td>Clear</td><td>0.0</td><td><code>page / 1.0</code> — passes through unchanged</td></tr></tbody></table><p>The multiplicative recovery correctly reverses anti-aliasing: dark text under a border pixel stays dark; a white background pixel is scaled back to white.</p><h2 id="ui-controls" tabindex="-1"><a class="header-anchor" href="#ui-controls"><span>UI Controls</span></a></h2><table><thead><tr><th>Control</th><th>ID</th><th>Effect</th></tr></thead><tbody><tr><td>Reveal strength</td><td><code>edge-subtract</code></td><td>0–255 → <code>uStrength</code> uniform</td></tr><tr><td>WebGL toggle</td><td><code>toggle-webgl</code></td><td>Shows/hides all <code>.webgl-overlay</code> canvases</td></tr></tbody></table><h2 id="context-limits" tabindex="-1"><a class="header-anchor" href="#context-limits"><span>Context Limits</span></a></h2><p>Browsers enforce ~16 simultaneous WebGL contexts. The lazy <code>IntersectionObserver</code> strategy ensures contexts are only allocated for pages with actual redactions, preventing <code>CONTEXT_LOST_WEBGL</code> crashes on large documents.</p>`,27)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};